prompt:
The following Hemlock program attempts to implement a work queue with workers but has multiple concurrency bugs. Fix all bugs so it produces the expected output.

```hemlock
// Work queue: 2 workers process items from a shared channel

async fn worker(id, jobs, results) {
    while (true) {
        let job = jobs.recv();
        if (job == null) {
            break;
        }
        // Process: square the number
        let result = job * job;
        results.send({ worker: id, input: job, output: result });
    }
}

let jobs = channel(5);
let results = channel(5);

// Spawn workers
let w1 = spawn(worker, 1, jobs, results);
let w2 = spawn(worker, 2, jobs, results);

// Send jobs
for (let i = 1; i <= 6; i++) {
    jobs.send(i);
}
jobs.close();

// Collect results
let total = 0;
for (let i = 0; i < 6; i++) {
    let r = results.recv();
    total += r.output;
}

print("total: " + total);

join(w1);
join(w2);
results.close();
print("done");
```

The sum of squares 1-6 is 1+4+9+16+25+36 = 91.

